{
  "model": "openai/alfred-brain",
  "messages": [
    {
      "role": "user",
      "content": "What rooms do I have on the first floor?"
    }
  ],
  "stream": true
}

{
  "model": "openai/alfred-brain",
  "messages": [
    {
      "role": "user",
      "content": "My name is Salih and I prefer the thermostat at 72 degrees"
    }
  ],
  "stream": true
}

{
  "model": "openai/alfred-brain",
  "messages": [
    {
      "role": "system",
      "content": "You are a helpful assistant. The following tools are available for controlling the smart home."
    },
    {
      "role": "user",
      "content": "Turn on the kitchen lights"
    }
  ],
  "tools": [
    {
      "type": "function",
      "function": {
        "name": "HassTurnOn",
        "description": "Turns on a device or entity",
        "parameters": {
          "type": "object",
          "properties": {
            "name": {
              "type": "string",
              "description": "Name of the device to turn on"
            },
            "area": {
              "type": "string",
              "description": "Area/room where the device is located"
            }
          },
          "required": ["name"]
        }
      }
    },
    {
      "type": "function",
      "function": {
        "name": "HassTurnOff",
        "description": "Turns off a device or entity",
        "parameters": {
          "type": "object",
          "properties": {
            "name": {
              "type": "string",
              "description": "Name of the device to turn off"
            },
            "area": {
              "type": "string",
              "description": "Area/room where the device is located"
            }
          },
          "required": ["name"]
        }
      }
    },
    {
      "type": "function",
      "function": {
        "name": "HassGetState",
        "description": "Gets the current state of a device or entity",
        "parameters": {
          "type": "object",
          "properties": {
            "name": {
              "type": "string",
              "description": "Name of the device to check"
            },
            "area": {
              "type": "string",
              "description": "Area/room where the device is located"
            }
          },
          "required": ["name"]
        }
      }
    }
  ],
  "stream": true,
  "stream_options": {
    "include_usage": true
  }
}

{
  "model": "openai/alfred-brain",
  "messages": [
    {
      "role": "user",
      "content": "What's the weather like?"
    },
    {
      "role": "assistant",
      "content": "Currently it's partly cloudy at 65°F, sir. Pleasant enough for the season."
    },
    {
      "role": "user",
      "content": "Should I take a jacket?"
    }
  ],
  "stream": true
}
